from torchvision.models import resnet18, resnet34, resnet50, resnet101, resnet152
import importlib

# %% ../../../nbs/02c_models.vision.resnets.ipynb #a224e474
class PretrainedResNet(nn.Module):

    def __init__(self, backbone, in_features, num_classes=10):
        super(PretrainedResNet, self).__init__()
        
        self.backbone = backbone
        self.head = nn.Linear(in_features, num_classes)

    def forward(self, x):
        h = self.backbone(x)
        h = h.view(h.size(0), -1)
        logits = self.head(h)
        return logits

# %% ../../../nbs/02c_models.vision.resnets.ipynb #c1677509
def resnetx(x= 18, num_classes= 1000):
    model_dict = {
        "resnet18": resnet18,
        "resnet34": resnet34,
        "resnet50": resnet50,
        "resnet101": resnet101,
        "resnet152": resnet152
    }
    
    model =  model_dict[f"resnet{x}"](weights= "IMAGENET1K_V1")
    in_features = model.fc.in_features
    l=[]
    for name, module in model.named_children():
        if name !='fc':
            l.append(module)
            
    backbone = nn.Sequential(*l)
    model = PretrainedResNet(backbone= backbone, in_features= in_features, num_classes= num_classes)

    return model

